import { useMemo } from 'react';
import { cn } from "./ui/utils";
import { RichTextEditorContext } from './rte-context';
import { DEFAULT_LABELS } from './labels';
import { Toolbar } from './rte-toolbar';
import { ControlsGroup } from './rte-controls-group';
import { Content } from './rte-content';
import { RichTextEditorControl } from './controls/rte-control';
import { LinkControl } from './controls/rte-link-control';
import * as controls from './controls/rte-controls';
import type { RichTextEditorProps } from './types';

function RichTextEditorRoot({
  editor,
  children,
  className,
  labels,
  variant = "default",
}: RichTextEditorProps) {
  const mergedLabels = useMemo(
    () => ({ ...DEFAULT_LABELS, ...labels }),
    [labels]
  );

  return (
    <RichTextEditorContext.Provider value={{ editor, labels: mergedLabels, variant }}>
      <div
        className={cn(
          'rte-root',
          variant !== "default" && `rte-root--${variant}`,
          className
        )}
        data-variant={variant}
      >
        {children}
      </div>
    </RichTextEditorContext.Provider>
  );
}

export const RichTextEditor = Object.assign(RichTextEditorRoot, {
  Toolbar,
  ControlsGroup,
  Content,
  Control: RichTextEditorControl,
  Link: LinkControl,
  Bold: controls.BoldControl,
  Italic: controls.ItalicControl,
  Underline: controls.UnderlineControl,
  Strikethrough: controls.StrikethroughControl,
  ClearFormatting: controls.ClearFormattingControl,
  Code: controls.CodeControl,
  CodeBlock: controls.CodeBlockControl,
  H1: controls.H1Control,
  H2: controls.H2Control,
  H3: controls.H3Control,
  H4: controls.H4Control,
  H5: controls.H5Control,
  H6: controls.H6Control,
  BulletList: controls.BulletListControl,
  OrderedList: controls.OrderedListControl,
  Blockquote: controls.BlockquoteControl,
  Hr: controls.HrControl,
  Unlink: controls.UnlinkControl,
  Undo: controls.UndoControl,
  Redo: controls.RedoControl,
  AlignLeft: controls.AlignLeftControl,
  AlignCenter: controls.AlignCenterControl,
  AlignRight: controls.AlignRightControl,
  AlignJustify: controls.AlignJustifyControl,
  Highlight: controls.HighlightControl,
  Subscript: controls.SubscriptControl,
  Superscript: controls.SuperscriptControl,
});

import { Editor } from "@tiptap/react";
import type { RichTextEditorLabels } from "./labels";
import type { RichTextEditorVariant } from "./types";
import { createContext, useContext } from "react";

interface RichTextEditorContextValue {
  editor: Editor | null;
  labels: RichTextEditorLabels;
  variant: RichTextEditorVariant;
}

export const RichTextEditorContext = createContext<RichTextEditorContextValue | null>(null);

export function useRichTextEditorContext(): RichTextEditorContextValue {
  const context = useContext(RichTextEditorContext);
  if (!context) {
    throw new Error(
      "useRichTextEditorContext must be used within RichTextEditor"
    );
  }
  return context;
}

import { cn } from "./ui/utils";
import { useRichTextEditorContext } from './rte-context';
import type { RichTextEditorToolbarProps } from './types';

export function Toolbar({
  children,
  className,
  sticky,
  stickyOffset = 0,
}: RichTextEditorToolbarProps) {
  const { variant } = useRichTextEditorContext();

  return (
    <div
      className={cn(
        'rte-toolbar',
        variant !== "default" && `rte-toolbar--${variant}`,
        sticky && 'sticky z-10',
        className
      )}
      data-sticky={sticky ? '' : undefined}
      style={sticky ? { top: stickyOffset } : undefined}
    >
      {children}
    </div>
  );
}

import { EditorContent } from "@tiptap/react";
import { cn } from "./ui/utils";
import { useRichTextEditorContext } from "./rte-context";
import type { RichTextEditorContentProps } from "./types";

export function Content({ className }: RichTextEditorContentProps) {
  const { editor } = useRichTextEditorContext();

  return (
    <EditorContent
      editor={editor}
      className={cn(
        "rte-content w-full",
        className
      )}
    />
  );
}

import { cn } from "./ui/utils";
import type { RichTextEditorControlsGroupProps } from './types';

export function ControlsGroup({
  children,
  className,
}: RichTextEditorControlsGroupProps) {
  return (
    <div
      className={cn('rte-controls-group', className)}
    >
      {children}
    </div>
  );
}

export interface RichTextEditorLabels {
    boldControlLabel: string;
    italicControlLabel: string;
    underlineControlLabel: string;
    strikeControlLabel: string;
    clearFormattingControlLabel: string;
    codeControlLabel: string;
    codeBlockControlLabel: string;
    h1ControlLabel: string;
    h2ControlLabel: string;
    h3ControlLabel: string;
    h4ControlLabel: string;
    h5ControlLabel: string;
    h6ControlLabel: string;
    bulletListControlLabel: string;
    orderedListControlLabel: string;
    blockquoteControlLabel: string;
    hrControlLabel: string;
    linkControlLabel: string;
    unlinkControlLabel: string;
    undoControlLabel: string;
    redoControlLabel: string;
    alignLeftControlLabel: string;
    alignCenterControlLabel: string;
    alignRightControlLabel: string;
    alignJustifyControlLabel: string;
    highlightControlLabel: string;
    subscriptControlLabel: string;
    superscriptControlLabel: string;
    tasksControlLabel: string;
    tasksSinkLabel: string;
    tasksLiftLabel: string;
    sourceCodeControlLabel: string;
    // link editor
    linkEditorInputLabel: string;
    linkEditorInputPlaceholder: string;
    linkEditorExternalLink: string;
    linkEditorInternalLink: string;
    linkEditorSave: string;
  }

  export const DEFAULT_LABELS: RichTextEditorLabels = {
    boldControlLabel: 'Bold',
    italicControlLabel: 'Italic',
    underlineControlLabel: 'Underline',
    strikeControlLabel: 'Strikethrough',
    clearFormattingControlLabel: 'Clear formatting',
    codeControlLabel: 'Code',
    codeBlockControlLabel: 'Code block',
    h1ControlLabel: 'Heading 1',
    h2ControlLabel: 'Heading 2',
    h3ControlLabel: 'Heading 3',
    h4ControlLabel: 'Heading 4',
    h5ControlLabel: 'Heading 5',
    h6ControlLabel: 'Heading 6',
    bulletListControlLabel: 'Bullet list',
    orderedListControlLabel: 'Ordered list',
    blockquoteControlLabel: 'Blockquote',
    hrControlLabel: 'Horizontal rule',
    linkControlLabel: 'Link',
    unlinkControlLabel: 'Remove link',
    undoControlLabel: 'Undo',
    redoControlLabel: 'Redo',
    alignLeftControlLabel: 'Align left',
    alignCenterControlLabel: 'Align center',
    alignRightControlLabel: 'Align right',
    alignJustifyControlLabel: 'Align justify',
    highlightControlLabel: 'Highlight',
    subscriptControlLabel: 'Subscript',
    superscriptControlLabel: 'Superscript',
    tasksControlLabel: 'Task list',
    tasksSinkLabel: 'Decrease task level',
    tasksLiftLabel: 'Increase task level',
    sourceCodeControlLabel: 'Source code',
    linkEditorInputLabel: 'Enter URL',
    linkEditorInputPlaceholder: 'https://example.com',
    linkEditorExternalLink: 'Open in new tab',
    linkEditorInternalLink: 'Open in same tab',
    linkEditorSave: 'Save',
  };

import type { Editor } from '@tiptap/react';
import type { RichTextEditorLabels } from './labels';

export type RichTextEditorVariant = "default" | "subtle" | "compact";

export interface RichTextEditorProps {
  editor: Editor | null;
  children: React.ReactNode;
  className?: string;
  labels?: Partial<RichTextEditorLabels>;
  variant?: RichTextEditorVariant;
}

export interface RichTextEditorToolbarProps {
  children: React.ReactNode;
  className?: string;
  sticky?: boolean;
  stickyOffset?: number | string;
}

export interface RichTextEditorContentProps {
  className?: string;
}

export interface RichTextEditorControlsGroupProps {
  children: React.ReactNode;
  className?: string;
}

export interface RichTextEditorControlProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  active?: boolean;
  interactive?: boolean;
}

.rte-root {
  position: relative;
  border-radius: var(--radius);
  border: 1px solid var(--border);
  background-color: var(--background);
}

.rte-content .ProseMirror {
  outline: 0;
  padding: var(--spacing, 0.75rem);
  min-height: 140px;
}

.rte-content .ProseMirror > *:last-child {
  margin-bottom: 0;
}

.rte-content .ProseMirror p.is-editor-empty:first-of-type::before {
  content: attr(data-placeholder);
  pointer-events: none;
  user-select: none;
  float: left;
  height: 0;
  color: var(--muted-foreground);
}

.rte-content .ProseMirror p {
  margin-top: 0;
  margin-bottom: 0.75rem;
  line-height: 1.75;
}

.rte-content .ProseMirror h1,
.rte-content .ProseMirror h2,
.rte-content .ProseMirror h3,
.rte-content .ProseMirror h4,
.rte-content .ProseMirror h5,
.rte-content .ProseMirror h6,
.rte-content .ProseMirror p {
  margin-top: 0;
}

.rte-content .ProseMirror h1 {
  font-size: 1.5rem;
  font-weight: 700;
  letter-spacing: -0.025em;
  margin-bottom: 1rem;
  margin-top: 1.5rem;
}

.rte-content .ProseMirror h1:first-child {
  margin-top: 0;
}

.rte-content .ProseMirror h2 {
  font-size: 1.25rem;
  font-weight: 600;
  letter-spacing: -0.025em;
  margin-bottom: 0.75rem;
