}

.rte-content .ProseMirror h2:first-child {
  margin-top: 0;
}

.rte-content .ProseMirror h3 {
  font-size: 1.125rem;
  font-weight: 600;
  margin-bottom: 0.5rem;
  margin-top: 1rem;
}

.rte-content .ProseMirror h3:first-child {
