  display: flex;
  align-items: center;
}
.rte-root[data-variant="default"] .rte-controls-group > button {
  border: 1px solid var(--border);
  border-radius: 0;
  min-width: 1.625rem;
  height: 1.625rem;
  background-color: var(--background);
}
.rte-root[data-variant="default"] .rte-controls-group > button:not(:last-of-type) {
  border-inline-end-width: 0;
}
.rte-root[data-variant="default"] .rte-controls-group > button:first-of-type {
  border-start-start-radius: calc(var(--radius) - 1px);
  border-end-start-radius: calc(var(--radius) - 1px);
}
.rte-root[data-variant="default"] .rte-controls-group > button:last-of-type {
  border-start-end-radius: calc(var(--radius) - 1px);
  border-end-end-radius: calc(var(--radius) - 1px);
}
.rte-root[data-variant="default"] .rte-controls-group > button:hover {
  background-color: var(--accent);
  color: var(--accent-foreground);
}
.rte-root[data-variant="default"] .rte-controls-group > button[data-state="on"],
.rte-root[data-variant="default"] .rte-controls-group > button[aria-pressed="true"] {
  background-color: var(--accent);
  color: var(--accent-foreground);
}

/* ── Subtle variant: borderless larger buttons ── */
.rte-root[data-variant="subtle"] {
  border-color: transparent;
}
.rte-toolbar--subtle {
  border-bottom: none;
  padding: 0.25rem;
  row-gap: 0;
  background-color: var(--muted);
}
.rte-root[data-variant="subtle"] .rte-controls-group {
  display: flex;
  align-items: center;
}
.rte-root[data-variant="subtle"] .rte-controls-group > button {
  border: none;
  border-radius: calc(var(--radius) - 2px);
  min-width: 2rem;
  height: 2rem;
  background-color: transparent;
}
.rte-root[data-variant="subtle"] .rte-controls-group > button:hover {
  background-color: var(--accent);
  color: var(--accent-foreground);
}
.rte-root[data-variant="subtle"] .rte-controls-group > button[data-state="on"],
.rte-root[data-variant="subtle"] .rte-controls-group > button[aria-pressed="true"] {
  background-color: var(--accent);
  color: var(--accent-foreground);
}

/* ── Compact variant: borderless smaller buttons ── */
.rte-root[data-variant="compact"] {
  border-radius: var(--radius);
}
.rte-toolbar--compact {
  padding: 0.25rem 0.375rem;
  gap: 0.125rem;
  border-bottom: none;
}
.rte-root[data-variant="compact"] .rte-controls-group {
  display: flex;
  align-items: center;
}
.rte-root[data-variant="compact"] .rte-controls-group > button {
  border: none;
  border-radius: calc(var(--radius) - 3px);
  min-width: 1.5rem;
  height: 1.5rem;
  background-color: transparent;
}
.rte-root[data-variant="compact"] .rte-controls-group > button:hover {
  background-color: var(--accent);
  color: var(--accent-foreground);
}
.rte-root[data-variant="compact"] .rte-controls-group > button[data-state="on"],
.rte-root[data-variant="compact"] .rte-controls-group > button[aria-pressed="true"] {
  background-color: var(--accent);
  color: var(--accent-foreground);
}
.rte-root[data-variant="compact"] .rte-controls-group > button svg {
  height: 0.75rem;
